/**
 * Get paginated assignments for a single worker.
 * @summary Get Worker Assignments
 */
export const getWorkerAssignments = (
  runId: string,
  workerName: string,
  params?: GetWorkerAssignmentsParams,
  options?: AxiosRequestConfig,
): Promise<AxiosResponse<PagedAssignmentsOut>> => {
  return axios.default.get(
    `/api/runs/${runId}/results/by-worker/${workerName}/assignments`,
    {
      ...options,
      params: { ...params, ...options?.params },
    },
  );
};

