/**
 * Get a bounded subgraph for the graph explorer.

Without focus params, returns the full graph if it's small enough,
otherwise returns metadata only so the UI can prompt for focus selection.
 * @summary Get Focused Graph
 */
export const getFocusedGraph = (
  runId: string,
  params?: GetFocusedGraphParams,
  options?: AxiosRequestConfig,
): Promise<AxiosResponse<GraphSubsetOut>> => {
  return axios.default.get(`/api/runs/${runId}/graph/focused`, {
    ...options,
    params: { ...params, ...options?.params },
  });
};

